import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { PhoneContact, Checklist, CallLog } from '../types';
import { encode, decode, decodeAudioData } from '../utils/audio-utils';

interface ActiveCallProps {
  contact: PhoneContact;
  checklist: Checklist;
  onFinished: (log: CallLog) => void;
  onClose: () => void;
}

const ActiveCall: React.FC<ActiveCallProps> = ({ contact, checklist, onFinished, onClose }) => {
  const [status, setStatus] = useState<'initiating' | 'ringing' | 'connected' | 'ended'>('initiating');
  const [duration, setDuration] = useState(0);
  const [transcription, setTranscription] = useState<{ speaker: 'agent' | 'user'; text: string }[]>([]);
  const [isMuted, setIsMuted] = useState(false);

  // Use number instead of NodeJS.Timeout for browser environment compatibility
  const timerRef = useRef<number | null>(null);
  const sessionRef = useRef<any>(null);
  const audioContextInRef = useRef<AudioContext | null>(null);
  const audioContextOutRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Language & Role Instructions
  const systemInstruction = `Ты — профессиональный и вежливый голосовой ассистент службы поддержки.
Твоя задача — провести опрос клиента по имени ${contact.name}. 
Ты звонишь на номер ${contact.number}.
Тема опроса: ${checklist.title}.
Твои шаги (чек-лист):
${checklist.items.map((it, i) => `${i + 1}. ${it}`).join('\n')}

ПРАВИЛА:
1. Говори только на русском языке.
2. Используй естественный, дружелюбный, человекоподобный голос.
3. Дождись ответа на каждый пункт чек-листа перед тем, как переходить к следующему.
4. В конце обязательно поблагодари за уделенное время.
5. Не используй текстовую разметку (Markdown), только чистую речь.`;

  useEffect(() => {
    // Initial Ringing State simulation
    const ringTimeout = setTimeout(() => {
      setStatus('ringing');
      const connTimeout = setTimeout(() => {
        handleConnect();
      }, 3000);
      return () => clearTimeout(connTimeout);
    }, 2000);

    return () => {
      clearTimeout(ringTimeout);
      stopCall();
    };
  }, []);

  useEffect(() => {
    if (status === 'connected') {
      // Explicitly use window.setInterval to ensure returning a number in browser context
      timerRef.current = window.setInterval(() => {
        setDuration(prev => prev + 1);
      }, 1000);
    } else {
      if (timerRef.current) {
        clearInterval(timerRef.current);
        timerRef.current = null;
      }
    }
    return () => { 
      if (timerRef.current) {
        clearInterval(timerRef.current);
        timerRef.current = null;
      }
    };
  }, [status]);

  const handleConnect = async () => {
    try {
      setStatus('connected');
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      audioContextInRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      audioContextOutRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
          },
          systemInstruction,
          outputAudioTranscription: {},
          inputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            console.log('Gemini Live session opened');
            const source = audioContextInRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = audioContextInRef.current!.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const l = inputData.length;
              const int16 = new Int16Array(l);
              for (let i = 0; i < l; i++) {
                int16[i] = inputData[i] * 32768;
              }
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };

              // Rely on sessionPromise to send data to avoid race conditions
              sessionPromise.then(session => {
                if (status === 'connected' && !isMuted) {
                  session.sendRealtimeInput({ media: pcmBlob });
                }
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextInRef.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            // Handle Audio Data
            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && audioContextOutRef.current) {
              const ctx = audioContextOutRef.current;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const audioBuffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(ctx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
              sourcesRef.current.add(source);
              source.onended = () => sourcesRef.current.delete(source);
            }

            // Handle Transcriptions
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              setTranscription(prev => [...prev, { speaker: 'agent', text }]);
            } else if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              setTranscription(prev => [...prev, { speaker: 'user', text }]);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e) => console.error('Gemini Live Error:', e),
          onclose: () => console.log('Gemini Live Session Closed'),
        }
      });

      sessionRef.current = await sessionPromise;

    } catch (err) {
      console.error("Connection failed", err);
      setStatus('ended');
    }
  };

  const stopCall = () => {
    if (sessionRef.current) {
      sessionRef.current.close();
      sessionRef.current = null;
    }
    audioContextInRef.current?.close();
    audioContextOutRef.current?.close();
    setStatus('ended');

    // Auto-save results
    const finalLog: CallLog = {
      id: Date.now().toString(),
      phoneNumber: contact.number,
      customerName: contact.name,
      status: 'completed',
      timestamp: new Date().toISOString(),
      transcript: transcription,
      summary: 'Опрос завершен успешно. Все пункты чек-листа пройдены.'
    };
    onFinished(finalLog);
  };

  const formatTime = (s: number) => {
    const mins = Math.floor(s / 60);
    const secs = s % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="fixed inset-0 z-50 bg-slate-900/95 flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-4xl rounded-3xl overflow-hidden shadow-2xl flex flex-col md:flex-row h-[80vh]">

        {/* Call Visualizer Side */}
        <div className="flex-1 bg-gradient-to-b from-indigo-600 to-indigo-900 p-8 flex flex-col items-center justify-center text-white relative">
          <button 
            onClick={onClose}
            className="absolute top-6 left-6 text-white/50 hover:text-white transition-colors"
          >
            <i className="fas fa-chevron-left mr-2"></i> Вернуться
          </button>

          <div className="relative mb-8">
            <div className={`w-32 h-32 rounded-full border-4 border-white/20 flex items-center justify-center text-4xl bg-white/10 ${
              status === 'connected' ? 'animate-pulse ring-8 ring-white/5' : ''
            }`}>
              <i className="fas fa-user"></i>
            </div>
            {status === 'connected' && (
              <div className="absolute -bottom-2 -right-2 bg-emerald-500 w-8 h-8 rounded-full border-4 border-indigo-700 flex items-center justify-center text-[10px]">
                <i className="fas fa-phone"></i>
              </div>
            )}
          </div>

          <h3 className="text-2xl font-bold">{contact.name}</h3>
          <p className="text-indigo-200 mt-1">{contact.number}</p>

          <div className="mt-8 text-center">
            {status === 'initiating' && <p className="text-white/60">Инициализация...</p>}
            {status === 'ringing' && <p className="animate-bounce">Идет вызов...</p>}
            {status === 'connected' && (
              <div className="space-y-4">
                <p className="text-emerald-300 font-mono text-xl">{formatTime(duration)}</p>
                <div className="flex gap-4">
                  <div className="w-1 h-8 bg-white/20 rounded-full animate-[pulse_1s_infinite]"></div>
                  <div className="w-1 h-12 bg-white/40 rounded-full animate-[pulse_0.8s_infinite]"></div>
                  <div className="w-1 h-16 bg-white/60 rounded-full animate-[pulse_1.2s_infinite]"></div>
                  <div className="w-1 h-12 bg-white/40 rounded-full animate-[pulse_0.9s_infinite]"></div>
                  <div className="w-1 h-8 bg-white/20 rounded-full animate-[pulse_1.1s_infinite]"></div>
                </div>
              </div>
            )}
          </div>

          <div className="mt-auto pt-8 flex gap-6">
            <button 
              onClick={() => setIsMuted(!isMuted)}
              className={`w-14 h-14 rounded-full flex items-center justify-center text-xl transition-all ${
                isMuted ? 'bg-amber-500 text-white' : 'bg-white/10 hover:bg-white/20 text-white'
              }`}
            >
              <i className={`fas ${isMuted ? 'fa-microphone-slash' : 'fa-microphone'}`}></i>
            </button>
            <button 
              onClick={stopCall}
              className="w-14 h-14 bg-red-500 hover:bg-red-600 rounded-full flex items-center justify-center text-xl text-white shadow-lg shadow-red-500/30"
            >
              <i className="fas fa-phone-slash"></i>
            </button>
          </div>
        </div>

        {/* Real-time Intel Side */}
        <div className="w-full md:w-[400px] flex flex-col bg-slate-50">
          <div className="p-6 border-b border-slate-200 bg-white">
            <h4 className="font-bold text-slate-800 flex items-center gap-2">
              <i className="fas fa-clipboard-list text-indigo-500"></i>
              Чек-лист: {checklist.title}
            </h4>
          </div>
          <div className="flex-1 overflow-y-auto p-6 space-y-4">
            <div className="space-y-2">
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Прогресс опроса</p>
              <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
                <ul className="space-y-3">
                  {checklist.items.map((item, i) => (
                    <li key={i} className="text-xs flex items-start gap-3 text-slate-600">
                       <i className="fas fa-circle-check mt-0.5 text-slate-200"></i>
                       {item}
                    </li>
                  ))}
                </ul>
              </div>
            </div>

            <div className="space-y-2">
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Транскрипция (Beta)</p>
              <div className="space-y-3">
                {transcription.length === 0 && (
                  <p className="text-xs text-slate-400 italic text-center py-8">Ожидание начала разговора...</p>
                )}
                {transcription.slice(-4).map((line, i) => (
                  <div key={i} className={`flex ${line.speaker === 'agent' ? 'justify-end' : 'justify-start'}`}>
                    <div className={`max-w-[80%] rounded-2xl px-4 py-2 text-xs shadow-sm ${
                      line.speaker === 'agent' 
                        ? 'bg-indigo-600 text-white rounded-br-none' 
                        : 'bg-white text-slate-700 rounded-bl-none border border-slate-200'
                    }`}>
                      {line.text}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

